mapper.select:
SELECT problemInfo.problem_id,problemInfo.problem_title,userInfo.`name` AS user_name, (SELECT GROUP_CONCAT( labelInfo.label_content ) FROM t_label_info labelInfo WHERE FIND_IN_SET( labelInfo.label_id, problemInfo.data_label )) AS data_label,problemInfo.is_top, problemInfo.create_time,problemTypeItem.item_text AS problem_type,problemInfo.problem_type AS problem_type_id, problemInfo.view_num,IF(ISNULL( problemComment.reply_num ), 0, problemComment.reply_num ) AS reply_num FROM t_problem_info problemInfo LEFT JOIN sys_user userInfo ON problemInfo.user_id = userInfo.user_id LEFT JOIN t_dict_item problemTypeItem ON problemInfo.problem_type = problemTypeItem.item_id LEFT JOIN ( SELECT count(*) AS reply_num, problem_id FROM t_problem_comment WHERE ISNULL( parent_comment_id ) GROUP BY problem_id ) problemComment ON problemInfo.problem_id = problemComment.problem_id
AND (problemInfo.problem_title LIKE concat(concat('%',#{problemInfo.problemTitle}),'%')
OR FIND_IN_SET(#{item.labelId},problemInfo.data_label)
)
AND problemInfo.problem_title LIKE concat(concat('%',#{problemInfo.problemTitle}),'%')
AND (
FIND_IN_SET(#{item.labelId},problemInfo.data_label)
)
AND DATE_FORMAT(problemInfo.create_time, '%Y-%m-%d') >= DATE_FORMAT(#{problemInfo.createTimeBegin}, '%Y-%m-%d')
AND DATE_FORMAT(problemInfo.create_time, '%Y-%m-%d') <= DATE_FORMAT(#{problemInfo.createTimeEnd}, '%Y-%m-%d')
AND problemInfo.user_id =#{problemInfo.userId}
AND problemInfo.problem_type =#{problemInfo.problemType}
ORDER BY problemInfo.is_top DESC, problemInfo.create_time DESC

mapper.update:
UPDATE t_problem_info
SET view_num = view_num + 1
WHERE problem_id=#{problemId}

mapper.select:
SELECT problemComment.comment_id,userInfo.`name` AS user_name,problemComment.create_time, problemComment.comment_content,userIntegral.integral_title,problemComment.user_id, problemCommentRecord.like_num,problemCommentRecord.tap_num,userOperationStatus.like_status, userOperationStatus.tap_status,childrenProblemComment.commentNum FROM t_problem_comment problemComment LEFT JOIN t_problem_comment_record problemCommentRecord ON problemComment.comment_id = problemCommentRecord.comment_id LEFT JOIN sys_user userInfo ON problemComment.user_id = userInfo.user_id LEFT JOIN ( SELECT userIntegral.user_id,userIntegral.integral_title FROM( SELECT DISTINCT( userIntegralInfo.user_id ),integralInfo.integral_title FROM t_user_integral_info userIntegralInfo LEFT JOIN t_integral_info integralInfo ON userIntegralInfo.integral_type = integralInfo.integral_type WHERE userIntegralInfo.integral_type = '1' AND userIntegralInfo.integral_num <= integralInfo.integral_num ORDER BY integralInfo.integral_num ) userIntegral GROUP BY userIntegral.user_id ) userIntegral ON problemComment.user_id = userIntegral.user_id LEFT JOIN ( SELECT max( CASE userOperation.operation_type WHEN '17' THEN 1 ELSE 0 END ) like_status, max( CASE userOperation.operation_type WHEN '18' THEN 1 ELSE 0 END ) tap_status, max( CASE userOperation.operation_type WHEN '19' THEN 1 ELSE 0 END ) collect_status, userOperation.event_id FROM t_user_operation_record userOperation
AND userOperation.user_id = #{userId}
AND userOperation.event_type = #{eventType}
GROUP BY userOperation.event_type,userOperation.event_id ) userOperationStatus ON problemComment.comment_id = userOperationStatus.event_id LEFT JOIN ( SELECT count(*) AS commentNum, parent_comment_id FROM t_problem_comment GROUP BY parent_comment_id ) childrenProblemComment ON problemComment.comment_id = childrenProblemComment.parent_comment_id
AND problemComment.problem_id=#{problemId}
AND problemComment.parent_comment_id =#{parentCommentId}
AND ISNULL( problemComment.parent_comment_id )

mapper.update:
UPDATE t_problem_comment_record
SET like_num = like_num + 1
WHERE comment_id=#{commentId}

UPDATE t_problem_comment_record
SET tap_num = tap_num + 1
WHERE comment_id=#{commentId}
